/**
 * @summary Get social content templates with captions
 */
export const getGetSocialTemplatesUrl = (params?: GetSocialTemplatesParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/social-templates?${stringifiedParams}`
    : `/api/social-templates`;
};

export const getSocialTemplates = async (
  params?: GetSocialTemplatesParams,
  options?: RequestInit,
): Promise<SocialTemplate[]> => {
  return customFetch<SocialTemplate[]>(getGetSocialTemplatesUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetSocialTemplatesQueryKey = (
  params?: GetSocialTemplatesParams,
) => {
  return [`/api/social-templates`, ...(params ? [params] : [])] as const;
};

export const getGetSocialTemplatesQueryOptions = <
  TData = Awaited<ReturnType<typeof getSocialTemplates>>,
  TError = ErrorType<unknown>,
>(
  params?: GetSocialTemplatesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getSocialTemplates>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetSocialTemplatesQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getSocialTemplates>>
  > = ({ signal }) => getSocialTemplates(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getSocialTemplates>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

